    React.createElement("mesh", { position: [6, 1.2, 0] }, React.createElement("octahedronGeometry", { args: [0.65, 0] }), React.createElement("meshStandardMaterial", { color: "#2c1f3f", emissive: "#a78bfa", emissiveIntensity: pipelineT > 0.7 ? 0.9 : 0.3 })),

    React.createElement(InfoPoint, { label: "CORPUS CLUSTERS", explanation: "Documents close in meaning cluster together in embedding space.", position: [-1.4, 2.6, -0.8], color: COLORS.topicA }),
